// Configuração obrigatória da Promise exigida pelo navegador
qz.api.setPromiseType(function (resolver) { 
    return new Promise(resolver); 
});

async function imprimirHtmlDoModal() {
	const statusTxt = document.getElementById("status");
	
	try {
		statusTxt.innerText = "Status: Conectando ao QZ Tray...";
		if (!qz.websocket.isActive()) {
			await qz.websocket.connect();
		}

		statusTxt.innerText = "Status: Preparando o HTML...";
		
		// CORREÇÃO: Força o QZ Tray a enviar o comando de corte automaticamente ao fim do HTML
		const config = qz.configs.create("Print ID", {
			cut: true // Ativa a guilhotina nativa do driver após a impressão do HTML
		}); 

		// Captura o HTML da div
		const conteudoHtmlDoModal = document.getElementById("meuModalHTML").innerHTML;

		// O array agora contém APENAS objetos do tipo pixel/html estruturados identicamente
		const dados = [
			{
				type: 'pixel', // Alinhado para o motor gráfico do QZ Tray
				format: 'html',
				flavor: 'plain',
				data: conteudoHtmlDoModal,
				options: {
					pageWidth: 3.1, // Define a largura fixa de ~80mm para a bobina térmica
					style: 'body { font-family: Arial; margin: 0; padding: 0; }' 
				}
			}
		];

		statusTxt.innerText = "Status: Enviando HTML para a Print ID...";
		await qz.print(config, dados);
		statusTxt.innerText = "Status: HTML enviado e impresso com sucesso!";

	} catch (erro) {
		console.error("Erro detalhado:", erro);
		statusTxt.innerText = "Erro no processo: " + erro.message;
	}
}